import React from 'react';

function Header() {
  return (
    <header className="text-center py-6 bg-gradient-to-r from-purple-700 via-indigo-700 to-purple-900 shadow-lg">
      <h1 className="text-3xl font-bold text-white">MeetingBot</h1>
      <p className="text-gray-300 mt-2">AI-Powered Audio & Text File Transcription with Summarization</p>
    </header>
  );
}

export default Header;


